import{_ as a,o as i,c as l,ag as t}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Calls State Modes and Limits","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/calls-deployment.md","filePath":"architecture/calls-deployment.md","lastUpdated":1775719799000}'),o={name:"architecture/calls-deployment.md"};function s(n,e,d,c,r,u){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="calls-state-modes-and-limits" tabindex="-1">Calls State Modes and Limits <a class="header-anchor" href="#calls-state-modes-and-limits" aria-label="Permalink to &quot;Calls State Modes and Limits&quot;">​</a></h1><p>This document defines how the Calls subsystem behaves in single-node and multi-node deployments.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Set <code>RUSTCHAT_CALLS_STATE_BACKEND</code>:</p><ul><li><code>memory</code>: single-node mode. Call state is process-local only.</li><li><code>redis</code>: multi-node mode. Call state is persisted to Redis and shared across instances.</li><li><code>auto</code> (default): use Redis when available; if Redis is unavailable for an operation, fall back to local in-memory state for that operation.</li></ul><p><code>RUSTCHAT_REDIS_URL</code> must point to the shared Redis instance in multi-node deployments.</p><h2 id="data-model-in-redis" tabindex="-1">Data Model in Redis <a class="header-anchor" href="#data-model-in-redis" aria-label="Permalink to &quot;Data Model in Redis&quot;">​</a></h2><p>When Redis mode is active, calls plugin state is stored as:</p><ul><li><code>rustchat:calls:state:&lt;call_id&gt;</code>: serialized call state JSON.</li><li><code>rustchat:calls:channel:&lt;channel_id&gt;</code>: <code>call_id</code> lookup.</li><li><code>rustchat:calls:active</code>: set of active call IDs.</li></ul><h2 id="single-node-behavior-memory" tabindex="-1">Single-Node Behavior (<code>memory</code>) <a class="header-anchor" href="#single-node-behavior-memory" aria-label="Permalink to &quot;Single-Node Behavior (`memory`)&quot;">​</a></h2><ul><li>All call state is in process memory.</li><li>Restarting the backend clears active call state.</li><li>Suitable for development and one-instance deployments.</li><li>No cross-instance visibility.</li></ul><h2 id="multi-node-behavior-redis-auto" tabindex="-1">Multi-Node Behavior (<code>redis</code>/<code>auto</code>) <a class="header-anchor" href="#multi-node-behavior-redis-auto" aria-label="Permalink to &quot;Multi-Node Behavior (`redis`/`auto`)&quot;">​</a></h2><ul><li>Read/write operations use Redis-backed call state.</li><li>Multiple backend instances can observe the same active calls.</li><li>SFU peer connections remain instance-local; this baseline shares control-plane call metadata only.</li></ul><h2 id="fallback-semantics-auto-and-redis-operation-failures" tabindex="-1">Fallback Semantics (<code>auto</code> and Redis operation failures) <a class="header-anchor" href="#fallback-semantics-auto-and-redis-operation-failures" aria-label="Permalink to &quot;Fallback Semantics (`auto` and Redis operation failures)&quot;">​</a></h2><ul><li>If Redis is unavailable during an operation, handlers continue with local memory state for continuity.</li><li>This allows degraded single-node behavior instead of hard failure.</li><li>During degraded operation, consistency across instances is not guaranteed.</li></ul><h2 id="websocket-signaling-delivery" tabindex="-1">WebSocket Signaling Delivery <a class="header-anchor" href="#websocket-signaling-delivery" aria-label="Permalink to &quot;WebSocket Signaling Delivery&quot;">​</a></h2><p>Server-generated signaling messages are emitted as websocket event:</p><ul><li>Event: <code>custom_com.mattermost.calls_signal</code></li><li>Delivery: direct to the target user via websocket hub</li><li>Payload fields: <ul><li><code>channel_id</code>, <code>channel_id_raw</code></li><li><code>user_id</code>, <code>user_id_raw</code></li><li><code>session_id</code>, <code>session_id_raw</code></li><li><code>signal</code> (<code>answer</code>, <code>ice-candidate</code>, <code>ice-state</code>, <code>connection-state</code>, etc.)</li></ul></li></ul><h2 id="current-limits-in-this-baseline" tabindex="-1">Current Limits in This Baseline <a class="header-anchor" href="#current-limits-in-this-baseline" aria-label="Permalink to &quot;Current Limits in This Baseline&quot;">​</a></h2><ul><li>No distributed SFU media plane yet; SFU sessions are local to the instance that owns the peer connection.</li><li>Redis operations are simple last-write-wins updates (no compare-and-swap conflict handling).</li><li>ICE candidate processing is complete for add/queue/flush flow, but advanced ICE retries/backoff policies are not yet implemented.</li></ul><h2 id="test-coverage" tabindex="-1">Test Coverage <a class="header-anchor" href="#test-coverage" aria-label="Permalink to &quot;Test Coverage&quot;">​</a></h2><ul><li>Integration tests cover call lifecycle websocket events and signaling delivery.</li><li>Unit tests cover ICE candidate parsing and call state backend mode parsing.</li></ul>',22)])])}const p=a(o,[["render",s]]);export{m as __pageData,p as default};
